import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"给主神的贡品","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/给主神的贡品.md","filePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/给主神的贡品.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/1.D级/给主神的贡品.md"};function _(l,a,i,b,p,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"给主神的贡品",tabindex:"-1"},[s("给主神的贡品 "),e("a",{class:"header-anchor",href:"#给主神的贡品","aria-label":'Permalink to "给主神的贡品"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风028")])])],-1),o('<h1 id="给主神的贡品-1" tabindex="-1">给主神的贡品 <a class="header-anchor" href="#给主神的贡品-1" aria-label="Permalink to &quot;给主神的贡品&quot;">​</a></h1><p>给主神的贡品<br> 奇物<br> D+500<br> 这是一个神龛，里面供奉着主神。<br> 平时会以一块刻着主神形象（大光球？）的令牌，在轮回者怀着虔诚之心呼唤主神之名时便会变成神龛。<br> 神龛木制的底座上有着神龛本体和一个盘子，神龛的造型和材质根据主神的形象改变。轮回者需要往盘子上放置符合主神胃口的贡品并向主神祈祷，在虔诚的祷告后，主神将会降下祝福。<br> 启动祝福是一个花招动作，该场景内，进行了上贡的轮回者在场景内随机获得以下效果中的一项：<br> *攻击轮回者的单位，会在攻击上承受劣化1（基于机运防御）。<br> *基于机运防御的1点全伤害吸收。<br> *从破甲/破魔/高速/威猛中选择一项，在攻击时获得5点对应破防能力。<br> *快速医疗1（医疗点数12）。<br> 场景内只会有一个轮回者能够享受这一好处，如果有任一轮回者在场景内已经使用了这一奇物，其他轮回者即使上供也无法享受到效果。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
